sb.AppendLine("    fraction_full DOUBLE,");
sb.AppendLine("    fraction_incremental DOUBLE,");
sb.AppendLine("    fraction_no_refresh DOUBLE,");

if (nodeMetrics != null)
{
    var knownPolicies = new[]
    {
        Common.Constants.FullRefreshPolicyValue,
        Common.Constants.IncrementalRefreshPolicyValue,
        Common.Constants.NoRefreshPolicyValue,
    };

    var terminalWithKnownPolicy = nodeMetrics.Values
        .Where(m => (m.Status == NodeExecutionStatus.Completed || m.Status == NodeExecutionStatus.Failed)
                    && knownPolicies.Any(p => string.Equals(m.RefreshPolicy, p, StringComparison.OrdinalIgnoreCase)))
        .ToList();

int denominator = terminalWithKnownPolicy.Count;
if (denominator > 0)
{
    row.FractionFull = (double)terminalWithKnownPolicy.Count(m =>
        string.Equals(m.RefreshPolicy, Common.Constants.FullRefreshPolicyValue, StringComparison.OrdinalIgnoreCase)) / denominator;
    row.FractionIncremental = (double)terminalWithKnownPolicy.Count(m =>
        string.Equals(m.RefreshPolicy, Common.Constants.IncrementalRefreshPolicyValue, StringComparison.OrdinalIgnoreCase)) / denominator;
    row.FractionNoRefresh = (double)terminalWithKnownPolicy.Count(m =>
        string.Equals(m.RefreshPolicy, Common.Constants.NoRefreshPolicyValue, StringComparison.OrdinalIgnoreCase)) / denominator;
}

